let tableName = $json.tableName;

if (!tableName) {
  const workflowData = $('When Executed by Another Workflow').first().json;
  tableName = workflowData.CLinicABBTable;
}

const cols = $input.first().json.value;

const headers = cols
  .slice()
  .sort((a, b) => (a.index ?? 0) - (b.index ?? 0))
  .map(c => c.name);

return [{
  json: {
    tableName,
    headers,
    headerCount: headers.length
  }
}];

// Get the raw string
const raw = $('When Executed by Another Workflow').first().json.textField2;

if (!raw) {
  return [{
    json: {
      PrescriberFirstName: null,
      PrescriberLastName: null,
      PrescriberNumber: null
    }
  }];
}

// Split and clean
let parts = raw.trim().split(/\s+/);

// Remove title if present
if (parts[0]?.toLowerCase() === 'dr') {
  parts.shift();
}

// Assign safely
const PrescriberFirstName = parts[0] ?? null;
const PrescriberLastName = parts[1] ?? null;
const PrescriberNumber = parts[2] ?? null;

return [{
  json: {
    PrescriberFirstName,
    PrescriberLastName,
    PrescriberNumber
  }
}];

const input = $input.first().json;

const address = String(input.address ?? '').trim();      // e.g. "WEL!A1:M2"
const cellValue = input.text?.[1]?.[0];                 // A2 (row 2, col A)

// Pull the end row number from the range (the number after the last column)
const m = address.match(/:([A-Z]+)(\d+)$/i);             // matches ":M2" -> ["...","M","2"]
const endRow = m ? Number(m[2]) : null;

let nextPatientNo;

// If we can't parse the address, fall back to cellValue logic
if (!endRow || Number.isNaN(endRow)) {
  const n = Number(cellValue);
  nextPatientNo = (!cellValue || Number.isNaN(n)) ? 1 : (n + 1);

} else if (endRow === 2) {
  // Special case: table bootstrap (header + 1 data row which may be blank)
  const n = Number(cellValue);
  nextPatientNo = (!cellValue || Number.isNaN(n)) ? 1 : (n + 1);

} else {
  // Once the range has grown beyond M2, the end row is the next patient number
  // M3 => 3, M4 => 4, etc.
  nextPatientNo = endRow;
}

return [{
  json: {
    address,
    endRow,
    currentValue: cellValue ?? null,
    nextPatientNo
  }
}];

// Get input safely
const inputJson = $input.first()?.json ?? {};

// Headers/tableName from the previous node
const headers = Array.isArray(inputJson.headers) ? inputJson.headers : [];
const tableName = inputJson.tableName ?? null;

if (!headers.length) {
  throw new Error(`Headers array is missing or empty. Input was: ${JSON.stringify(inputJson)}`);
}

// Parent workflow payload
const parent = $('When Executed by Another Workflow').first().json;

// Next patient number
const nextPatientNoRaw = $('PaintentNumberCheck').first().json.nextPatientNo;
const nextPatientNo = Number(nextPatientNoRaw);

if (Number.isNaN(nextPatientNo)) {
  throw new Error(`nextPatientNo is not a number. Got: ${nextPatientNoRaw}`);
}

// Prescriber values
const dr = $('DrDetailCleanUp')?.first?.().json ?? {};
const PRESCRIBER_FIRST = dr.PrescriberFirstName ?? null;
const PRESCRIBER_LAST = dr.PrescriberLastName ?? null;
const PRESCRIBER_NO = dr.PrescriberNumber ?? null;

// Product values
const productRow = $('Get row(s)')?.first?.().json ?? {};
const PRODUCT_NAME = productRow.DrugName ?? null;
const PRODUCT_CODE = productRow.ZenotiProductCode ?? null;
const CL_PRODUCT_CODE = productRow.DrugReferenceCode ?? null;
const UNIT_COST = Number(productRow.Cost ?? 0);

// RegionCheck values
const region = $("Call 'ZenotiNZ - RegionCheck'")?.first?.().json ?? {};
const ITEM_COUNT = Number(region.quantity ?? parent.quantity ?? 0);
const DELIVERY_LOCATION = region.DeliveryLocation ?? null;
const CUSTOMER_CODE = region.CustomerCode ?? null;

// New preferred region source
const joinSplit = $('JoinSplitRegions')?.first?.().json ?? {};
const JOIN_REGION_TEXT = joinSplit.Region ?? joinSplit['Address Shipping'] ?? null;

// Fallback to original RegionCheck Region if JoinSplitRegions is empty
const REGION_TEXT = JOIN_REGION_TEXT ?? region.Region ?? null;

// Shipping cost
const SHIPPING_COST_RAW = $('MedsShippingCost')?.first?.().json?.ShippingCost;
const SHIPPING_COST = Number(SHIPPING_COST_RAW ?? 0);

// Start date mapped into OrderDate
const START_DATE = $('When Executed by Another Workflow').first().json.StartDate ?? null;

// ProductCost = unit cost × item count
const PRODUCT_COST =
  (Number.isFinite(UNIT_COST) ? UNIT_COST : 0) *
  (Number.isFinite(ITEM_COUNT) ? ITEM_COUNT : 0);

// Build one output row aligned to the Excel headers
const row = headers.map(h => {
  switch (h) {
    case 'Patient No':
      return nextPatientNo;

    case 'Customer First Name':
      return parent.CustomerFirstName ?? null;

    case 'Customer Last Name':
      return parent.CustomerLastName ?? null;

    case 'Email Address':
      return parent.CustomerEmail ?? null;

    case 'Gender':
      return parent.CustomerGender ?? null;

    case 'DOB':
      return parent.CustomerDOB ?? null;

    case 'Product Name':
      return PRODUCT_NAME;

    case 'Quantity':
      return 100;

    case 'Item Count':
      return ITEM_COUNT || null;

    case 'Delivery Address':
      return parent.DeliveryAddressFull ?? null;

    case 'Prescriber First Name':
      return PRESCRIBER_FIRST;

    case 'Prescriber Last Name':
      return PRESCRIBER_LAST;

    case 'Prescriber No':
      return PRESCRIBER_NO;

    case 'Regional':
      return REGION_TEXT;

    case 'ProductCode':
      return PRODUCT_CODE;

    case 'ProductCost':
      return PRODUCT_COST;

    case 'CustomerCode':
      return CUSTOMER_CODE;

    case 'Shipping Cost':
      return SHIPPING_COST;

    case 'DeliveryLocation':
      return DELIVERY_LOCATION;

    case 'CLProductCode':
      return CL_PRODUCT_CODE;

    case 'Unit Price':
      return UNIT_COST;

    case 'OrderDate':
      return START_DATE;

    default:
      return null;
  }
});

// Graph expects a 2D array
return [{
  json: {
    tableName,
    values: [row]
  }
}];

const items = $('When Executed by Another Workflow').all();

// Set once
const AddedtoFinanceSpreadSheet = true;

for (const item of items) {
  item.json.AddedtoFinanceSpreadSheet = AddedtoFinanceSpreadSheet;
}

return items;

